document.body.style.overflow = 'hidden';
function buildName(elId, word, baseDelay) {
  const el = document.getElementById(elId);
  word.split('').forEach((ch, i) => {
    const s = document.createElement('span');
    s.classList.add('letter');
    s.textContent = ch;
    s.style.animationDelay = (baseDelay + i * 0.09) + 's';
    el.appendChild(s);
  });
}
buildName('row1', 'AREMOMHE', 0);
buildName('row2', 'REMY', 0.85);

function startHero() {
  document.querySelectorAll('.letter').forEach(l => l.style.animationPlayState = 'running');
  const role = document.querySelector('.role');
  const socials = document.querySelector('.socials');
  const scrollCue = document.querySelector('.scroll-cue');
  const scrollLine = document.querySelector('.scroll-line');
  role.style.animationDelay = '1.8s';
  role.style.animationPlayState = 'running';
  socials.style.animationDelay = '2.3s';
  socials.style.animationPlayState = 'running';
  scrollCue.style.animationDelay = '3s';
  scrollCue.style.animationPlayState = 'running';
  scrollLine.style.animationPlayState = 'running';
}

const canvas = document.getElementById('draw-canvas');
const ctx = canvas.getContext('2d');
const wrap = document.getElementById('canvas-wrap');
const dot = document.getElementById('pencil-dot');
const sketchImg = document.getElementById('sketch-final');
const drawLabel = document.getElementById('draw-label');

canvas.width = wrap.offsetWidth;
canvas.height = wrap.offsetHeight;

const offscreen = document.createElement('canvas');
const offCtx = offscreen.getContext('2d');
const img = new Image();
img.src = 'data:image/png;base64,';

img.onload = () => {
  offscreen.width = canvas.width;
  offscreen.height = canvas.height;
  offCtx.drawImage(img, 0, 0, canvas.width, canvas.height);
  const imageData = offCtx.getImageData(0, 0, canvas.width, canvas.height);
  const pixels = imageData.data;

  const brightPixels = [];
  for (let y = 0; y < canvas.height; y++) {
    for (let x = 0; x < canvas.width; x++) {
      const idx = (y * canvas.width + x) * 4;
      const brightness = pixels[idx];
      if (brightness > 20) {
        brightPixels.push({ x, y, b: brightness });
      }
    }
  }

  // Sort top-to-bottom with slight horizontal variance — feels like natural sketching
  brightPixels.sort((a, b) => {
    const yDiff = a.y - b.y;
    if (Math.abs(yDiff) > 6) return yDiff;
    return a.x - b.x;
  });

  const totalPixels = brightPixels.length;
  const drawDuration = 4500;
  const pixelsPerFrame = Math.ceil(totalPixels / (drawDuration / 16));

  let drawn = 0;
  dot.style.opacity = '1';
  ctx.fillStyle = '#000';
  ctx.fillRect(0, 0, canvas.width, canvas.height);

  function drawFrame() {
    const end = Math.min(drawn + pixelsPerFrame, totalPixels);
    for (let i = drawn; i < end; i++) {
      const p = brightPixels[i];
      const alpha = p.b / 255;
      ctx.fillStyle = `rgba(${p.b},${p.b},${p.b},${alpha})`;
      ctx.fillRect(p.x, p.y, 1, 1);
    }
    drawn = end;

    if (drawn < totalPixels) {
      const cur = brightPixels[drawn - 1];
      const scaleX = wrap.offsetWidth / canvas.width;
      const scaleY = wrap.offsetHeight / canvas.height;
      dot.style.left = (cur.x * scaleX) + 'px';
      dot.style.top  = (cur.y * scaleY) + 'px';
    }

    const progress = Math.round((drawn / totalPixels) * 100);
    drawLabel.textContent = progress < 100 ? `sketching... ${progress}%` : '';

    if (drawn < totalPixels) {
      requestAnimationFrame(drawFrame);
    } else {
      dot.style.opacity = '0';
      sketchImg.style.opacity = '1';
      canvas.style.opacity = '0';

      setTimeout(() => {
        document.getElementById('drawing-stage').classList.add('zoom-out');
        setTimeout(() => {
          document.getElementById('drawing-stage').style.display = 'none';
          document.getElementById('hero').classList.add('visible');
          document.body.style.overflow = '';
          startHero();
        }, 1600);
      }, 800);
    }
  }

  setTimeout(() => requestAnimationFrame(drawFrame), 400);
};


// Last.fm Now Playing
const LASTFM_USER = 'Rv3my'; // <-- replace this
const LASTFM_API_KEY = '248965a0017aa3f8ee2ab5f4440785e8';       // <-- replace this

async function fetchNowPlaying() {
  const url = `https://ws.audioscrobbler.com/2.0/?method=user.getrecenttracks&user=${LASTFM_USER}&api_key=${LASTFM_API_KEY}&format=json&limit=1`;

  try {
    const res = await fetch(url);
    const data = await res.json();
    const track = data.recenttracks.track[0];
    const isPlaying = track['@attr']?.nowplaying === 'true';

    const widget = document.getElementById('nowPlaying');
    if (!isPlaying) {
      widget.classList.add('hidden');
      return;
    }

    widget.classList.remove('hidden');
    document.getElementById('npTrack').textContent = track.name;
    document.getElementById('npArtist').textContent = track.artist['#text'];

    const img = track.image.find(i => i.size === 'large')?.['#text'];
    const albumImg = document.getElementById('npAlbumArt');
    albumImg.src = img || '';
  } catch (e) {
    console.error('Now playing fetch failed', e);
  }
}

fetchNowPlaying();
setInterval(fetchNowPlaying, 30000); // refresh every 30s

const testimonials = [
  {
    text: "Aremomhe stands out because of her ability to deliver exactly what you asked for, she's a top notch communicator and a very versatile developer.",
    name: "— CEO of tulips and roses"
  },
  {
    text: "One of the most detail-oriented developers I've worked with.",
    name: "— StayWoke Luxury"
  },
  {
    text: "You don't fully believe it until you experience it yourself. Remy never disappoints",
    name: "— Undisclosed"
  }
];

let testiIndex = 0;

function typeTestimonial(text, callback) {
  const el = document.getElementById('testiText');
  el.textContent = '';
  el.style.borderRight = '2px solid #fff';
  let i = 0;
  const interval = setInterval(() => {
    el.textContent += text[i];
    i++;
    if (i >= text.length) {
      clearInterval(interval);
      el.style.borderRight = 'none';
      if (callback) callback();
    }
  }, 38);
}

function showTestimonial() {
  const testi = testimonials[testiIndex];
  const author = document.getElementById('testiAuthor');
  const name = document.getElementById('testiName');

  author.classList.remove('visible');
  name.textContent = testi.name;

  typeTestimonial(testi.text, () => {
    setTimeout(() => {
      author.classList.add('visible');
      setTimeout(() => {
        testiIndex = (testiIndex + 1) % testimonials.length;
        showTestimonial();
      }, 6000);
    }, 300);
  });
}

// Start when section is in view
const testiObserver = new IntersectionObserver((entries) => {
  entries.forEach(entry => {
    if (entry.isIntersecting) {
      showTestimonial();
      testiObserver.disconnect();
    }
  });
}, { threshold: 0.3 });

testiObserver.observe(document.getElementById('testimonials'));